let text = $('Agente RAG').last().json.output || "";
text = text.replace(/<think>[\s\S]*?<\/think>/g, "").trim();

try {
  // Parsear observation de Qdrant
  const observationString = $json.intermediateSteps[0].observation;
  const qdrantItems = observationString ? JSON.parse(observationString) : [];

  const archivos = new Set();

  // Iterar sobre cada item y extraer metadata.nombre, excluyendo .eml
  for (const item of qdrantItems) {
    if (item.type === "text" && item.text) {
      try {
        const data = JSON.parse(item.text);
        const nombre = data.metadata?.nombre;
        if (nombre && !nombre.toLowerCase().endsWith(".eml")) {
          archivos.add(nombre);
        }
      } catch (e) {
        // ignorar JSON inválido
      }
    }
  }

  // Añadir hasta 3 nombres de ficheros al final
  if (archivos.size > 0) {
    const lista = Array.from(archivos).slice(0, 3);
    text += "\n\n📚 Fuentes/Sources:\n" + lista.map(f => `• ${f}`).join("\n");
  }

} catch (error) {
  console.log("No se pudo procesar la observación de Qdrant:", error);
}

// 👉 FRASE FINAL SIEMPRE
text += "\n\n---\nSi no te ha resultado de ayuda o necesitas que relaciones internacionales se ponga en contacto contigo, solicita el formulario de contacto en el chat.";

return { output: text };

// Obtener los datos de entrada
const data = $input.item.json;

// Inicializar variables
let problema = null;
let respuesta = null;

// Verificar que exista el array de mensajes y que tenga al menos 1 elemento
if (data.messages && Array.isArray(data.messages) && data.messages.length >= 1) {

  // Obtener el penúltimo mensaje
  const lastMessage = data.messages[data.messages.length - 1];

  // Separar problema y respuesta
  problema = lastMessage.human || null;
  respuesta = lastMessage.ai || null;
}

// Devolver el resultado separado
return {
  json: {
    problema,
    respuesta
  }
};

